-- Phase 2, Topic 5: "I Am Working Now" - Present Continuous (Right Now Actions)
-- 30 questions (12 easy, 12 medium, 6 hard)
-- Pattern-based, beginner-friendly, Indian context

INSERT INTO english_questions (path_id, topic_id, level, question, options, correct_answer, explanation, difficulty) VALUES

-- EASY QUESTIONS (12) - Basic present continuous structure
('foundation', 'present-continuous', 'beginner', 'I _____ working now.', '["am", "is", "are", "be"]', 0, 'Pattern: I + am + [verb + ing]. Use "am" with I. Add -ing to verb: work + ing = working.', 'easy'),

('foundation', 'present-continuous', 'beginner', 'She _____ cooking dinner.', '["am", "is", "are", "be"]', 1, 'Pattern: He/She/It + is + [verb + ing]. Use "is" with she. Add -ing: cook + ing = cooking.', 'easy'),

('foundation', 'present-continuous', 'beginner', 'They _____ playing cricket.', '["am", "is", "are", "be"]', 2, 'Pattern: They/We/You + are + [verb + ing]. Use "are" with they. Add -ing: play + ing = playing.', 'easy'),

('foundation', 'present-continuous', 'beginner', 'He _____ reading a book.', '["am", "is", "are", "be"]', 1, 'Pattern: He + is + [verb + ing]. Use "is" with he. Add -ing: read + ing = reading.', 'easy'),

('foundation', 'present-continuous', 'beginner', 'We _____ watching TV.', '["am", "is", "are", "be"]', 2, 'Pattern: We + are + [verb + ing]. Use "are" with we. Add -ing: watch + ing = watching.', 'easy'),

('foundation', 'present-continuous', 'beginner', 'It _____ raining outside.', '["am", "is", "are", "be"]', 1, 'Pattern: It + is + [verb + ing]. Use "is" with it. Weather verb: rain + ing = raining.', 'easy'),

('foundation', 'present-continuous', 'beginner', 'I am _____ to music.', '["listen", "listens", "listening", "listened"]', 2, 'Pattern: I + am + [verb + ing]. Add -ing to verb: listen + ing = listening. Present continuous shows action happening RIGHT NOW.', 'easy'),

('foundation', 'present-continuous', 'beginner', 'She is _____ her homework.', '["do", "does", "doing", "did"]', 2, 'Pattern: She + is + [verb + ing]. Add -ing: do + ing = doing. Present continuous = happening now.', 'easy'),

('foundation', 'present-continuous', 'beginner', 'They are _____ coffee.', '["drink", "drinks", "drinking", "drank"]', 2, 'Pattern: They + are + [verb + ing]. Add -ing: drink + ing = drinking. Action happening right now.', 'easy'),

('foundation', 'present-continuous', 'beginner', 'You _____ studying hard.', '["am", "is", "are", "be"]', 2, 'Pattern: You + are + [verb + ing]. Use "are" with you (always "are", never "am" or "is"). Verb: study + ing = studying.', 'easy'),

('foundation', 'present-continuous', 'beginner', 'My brother _____ sleeping.', '["am", "is", "are", "be"]', 1, 'Pattern: My brother = he + is + [verb + ing]. Use "is" with singular nouns. Sleep + ing = sleeping.', 'easy'),

('foundation', 'present-continuous', 'beginner', 'The children are _____ in the park.', '["play", "plays", "playing", "played"]', 2, 'Pattern: The children = they + are + [verb + ing]. Add -ing: play + ing = playing. Continuous = action in progress.', 'easy'),

-- MEDIUM QUESTIONS (12) - Time markers, spelling rules
('foundation', 'present-continuous', 'beginner', 'I am _____ an email. (Spelling rule: drop silent e)', '["writeing", "writing", "writting", "writes"]', 1, 'Spelling rule: When verb ends in silent e, drop e + add ing. Write → drop e → writ + ing = writing. Also: make → making, take → taking.', 'medium'),

('foundation', 'present-continuous', 'beginner', 'She is _____ for the bus. (Double consonant rule)', '["runing", "running", "runs", "runned"]', 1, 'Spelling rule: Short vowel + one consonant → double consonant + ing. Run → runn + ing = running. Also: swim → swimming, sit → sitting.', 'medium'),

('foundation', 'present-continuous', 'beginner', 'Arrange correctly: now / is / He / tea / drinking', '["He is drinking tea now", "He is now drinking tea", "Now he is drinking tea", "He drinking is tea now"]', 0, 'Pattern: He + is + [verb + ing] + [object] + now. "Now" usually goes at end. Order: subject + is/am/are + verb-ing + what + time marker.', 'medium'),

('foundation', 'present-continuous', 'beginner', 'What is wrong? "She working on a project."', '["Add is before working", "Use works instead of working", "Use worked instead of working", "Nothing wrong"]', 0, 'Missing verb "to be"! Pattern: She + IS + [verb + ing]. Correct: "She is working on a project." Never just "subject + verb-ing" - must have am/is/are.', 'medium'),

('foundation', 'present-continuous', 'beginner', 'Choose the sentence about an action happening RIGHT NOW:', '["I work from home.", "I am working from home.", "I worked from home.", "I will work from home."]', 1, 'Present continuous = happening NOW (this moment). Pattern: I + am + [verb + ing]. "I am working" = right now. "I work" = general habit (not now).', 'medium'),

('foundation', 'present-continuous', 'beginner', 'On a phone call, explaining what you''re doing:', '["I driving right now.", "I am drive right now.", "I am driving right now.", "I drives right now."]', 2, 'Pattern: I + am + [verb + ing] + right now. Must have "am". Verb: drive → drop e → driv + ing = driving. "Right now" = common time marker.', 'medium'),

('foundation', 'present-continuous', 'beginner', 'What is the error? "They is watching a movie."', '["Use are instead of is", "Use watch instead of watching", "Use watched instead of watching", "Nothing wrong"]', 0, 'Pattern error: They = are (not is). Correct: "They are watching a movie." I → am, He/She/It → is, You/We/They → are.', 'medium'),

('foundation', 'present-continuous', 'beginner', 'Rearrange: at / moment / the / studying / We / are', '["We are studying at the moment", "We are at the moment studying", "At the moment we are studying", "We studying are at the moment"]', 0, 'Pattern: We + are + [verb + ing] + at the moment. "At the moment" = common phrase = happening now. Can also start: "At the moment, we are studying."', 'medium'),

('foundation', 'present-continuous', 'beginner', 'Choose the correct spelling:', '["He is siting on the chair.", "He is sitting on the chair.", "He is sitted on the chair.", "He is sits on the chair."]', 1, 'Spelling rule: Short vowel + one consonant → double. Sit → sitt + ing = sitting. Correct: "He is sitting on the chair."', 'medium'),

('foundation', 'present-continuous', 'beginner', 'At work, your colleague asks "What are you doing?" You say:', '["I work on a report.", "I am work on a report.", "I am working on a report.", "I working on a report."]', 2, 'Pattern: I + am + [verb + ing]. Must have "am" + verb-ing. Correct: "I am working on a report." Answer matches the question tense.', 'medium'),

('foundation', 'present-continuous', 'beginner', 'What is wrong? "She is haveing lunch."', '["Spell it as having (drop e)", "Use has instead of having", "Use had instead of having", "Nothing wrong"]', 0, 'Spelling rule: Drop silent e before -ing. Have → drop e → hav + ing = having (not "haveing"). Correct: "She is having lunch."', 'medium'),

('foundation', 'present-continuous', 'beginner', 'Arrange correctly: to / listening / I / am / music', '["I am listening to music", "I am to listening music", "I listening am to music", "Am I listening to music"]', 0, 'Pattern: I + am + [verb + ing] + to + [thing]. Phrasal verb "listen to" stays together. Order: I am listening to music (statement, not question).', 'medium'),

-- HARD QUESTIONS (6) - Stative verbs, temporary vs permanent
('foundation', 'present-continuous', 'beginner', 'What is wrong? "I am knowing the answer."', '["Use know instead (no continuous)", "Use knows instead", "Use knew instead", "Nothing wrong"]', 0, 'Stative verb error! "Know" = mental state (not action), never use continuous. Correct: "I know the answer." Other stative verbs: understand, love, hate, want, need, believe - NO -ing form.', 'hard'),

('foundation', 'present-continuous', 'beginner', 'Which is correct for a TEMPORARY situation (this month only)?', '["I work from home.", "I am working from home.", "I worked from home.", "I will work from home."]', 1, 'Present continuous for TEMPORARY situations! Pattern: I + am + [verb + ing]. "I am working from home" = temporary (this week/month). "I work from home" = permanent habit.', 'hard'),

('foundation', 'present-continuous', 'beginner', 'Find the error: "She is having a car."', '["Use has (have = possession, no continuous)", "Use have instead of having", "Use had instead of having", "No error"]', 0, 'Stative verb! "Have" for possession never uses continuous. Correct: "She has a car." BUT "She is having lunch" is OK (having = eating = action, not possession).', 'hard'),

('foundation', 'present-continuous', 'beginner', 'Arrange correctly: days / staying / these / here / I / am', '["I am staying here these days", "I am these days staying here", "These days I am staying here", "I staying am here these days"]', 0, 'Pattern: I + am + [verb + ing] + [place] + these days. "These days" = time expression = temporary. Natural order: I am staying here these days. Can also start with time.', 'hard'),

('foundation', 'present-continuous', 'beginner', 'What is wrong? "They are wanting more money."', '["Use want (no continuous with want)", "Use wants instead of wanting", "Use wanted instead of wanting", "Nothing wrong"]', 0, 'Stative verb error! "Want" = desire (state), no continuous. Correct: "They want more money." Mental state verbs (want, need, prefer, like) never take -ing.', 'hard'),

('foundation', 'present-continuous', 'beginner', 'Which sentence is grammatically perfect for describing what you see NOW?', '["Look! The bus comes.", "Look! The bus is coming.", "Look! The bus come.", "Look! The bus coming."]', 1, 'Pattern: Look! + [subject] + is/are + [verb + ing]. "Look!" signals something happening RIGHT NOW. Correct: "The bus is coming." Must have "is" + verb-ing.', 'hard');

-- Verify insertion
SELECT COUNT(*) as total_inserted FROM english_questions WHERE topic_id = 'present-continuous';
